const uint8_t *FontBig72x96_GetGlyph(char ch, int &width, int &height, int &strideBytes) {
    int idx = CharIndex(ch);
    if (idx < 0) return nullptr;
    width = kFontBig72x96_Width;
    height = kFontBig72x96_Height;
    strideBytes = kFontBig72x96_Stride;
    return kFontBig72x96_Glyphs[idx];
}

